const express = require('express');
const session = require('express-session');
const jwt = require('jsonwebtoken');
const axios = require('axios');
const bodyParser = require('body-parser');
const querystring = require('querystring');
const { URL } = require('url');

const app = express();
const PORT = process.env.PORT || 3000;

const OIDC_CONFIG = {
    clientId: 'YOUR_CLIENT_ID',
    clientSecret: 'YOUR_CLIENT_SECRET',
    redirectUri: 'http://localhost:3000/callback',
    issuer: 'https://your-issuer.com',
    tokenEndpoint: 'https://your-issuer.com/token',
    userinfoEndpoint: 'https://your-issuer.com/userinfo',
};

app.use(bodyParser.urlencoded({ extended: true }));
app.use(session({
    secret: 'YOUR_SESSION_SECRET',
    resave: false,
    saveUninitialized: true,
}));

app.get('/login', (req, res) => {
    const authUrl = new URL('https://your-issuer.com/auth');
    authUrl.searchParams.append('response_type', 'code');
    authUrl.searchParams.append('client_id', OIDC_CONFIG.clientId);
    authUrl.searchParams.append('redirect_uri', OIDC_CONFIG.redirectUri);
    authUrl.searchParams.append('scope', 'openid email profile');
    res.redirect(authUrl.toString());
});

app.get('/callback', async (req, res) => {
    const { code } = req.query;
    if (!code) {
        return res.status(400).send('Authorization code is missing');
    }

    try {
        const tokenResponse = await axios.post(OIDC_CONFIG.tokenEndpoint, querystring.stringify({
            grant_type: 'authorization_code',
            code,
            redirect_uri: OIDC_CONFIG.redirectUri,
            client_id: OIDC_CONFIG.clientId,
            client_secret: OIDC_CONFIG.clientSecret,
        }), {
            headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
        });

        const { id_token } = tokenResponse.data;
        const decodedToken = jwt.decode(id_token);

        if (!decodedToken || !decodedToken.sub || !decodedToken.email || !decodedToken.name) {
            return res.status(401).send('Invalid ID token');
        }

        req.session.user = {
            sub: decodedToken.sub,
            email: decodedToken.email,
            name: decodedToken.name,
        };

        res.redirect('/profile');
    } catch (error) {
        console.error('Error exchanging code for tokens:', error);
        res.status(500).send('Authentication failed');
    }
});

app.get('/profile', (req, res) => {
    if (!req.session.user) {
        return res.status(401).send('Unauthorized');
    }
    res.send(`Hello, ${req.session.user.name}. Your email is ${req.session.user.email}.`);
});

app.listen(PORT, () => {
    console.log(`Server is running on http://localhost:${PORT}`);
});